import{_ as e,a,b as d,c as o,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as l,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Додавання каналу Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/dropbox.md","filePath":"uk-UA/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"uk-UA/upload/dropbox.md"};function h(b,t,u,m,x,g){return l(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="додавання-каналу-dropbox" tabindex="-1">Додавання каналу Dropbox <a class="header-anchor" href="#додавання-каналу-dropbox" aria-label="Permalink to &quot;Додавання каналу Dropbox&quot;">​</a></h1><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Dropbox</td><td>Для входу й авторизації app</td></tr><tr><td>Dropbox app</td><td>Для отримання <code>App Key</code> і <code>App Secret</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI</td></tr><tr><td>Доступне сховище Dropbox</td><td>Фактичне місце зберігання файлів</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-створіть-dropbox-app" tabindex="-1">Крок 1. Створіть Dropbox app <a class="header-anchor" href="#крок-1-створіть-dropbox-app" aria-label="Permalink to &quot;Крок 1. Створіть Dropbox app&quot;">​</a></h3><ol><li>Відкрийте Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Створіть новий app.</li><li>Для access type виберіть:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Дайте app зрозумілу назву, наприклад <code>imgbed-app</code>.</li><li>Після створення відкрийте сторінку деталей app.</li></ol><p>Рекомендований тип доступу:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Рекомендація</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Рекомендовано. Це відповідає тому, як ImgBed зберігає файли.</td></tr><tr><td><code>Full Dropbox</code></td><td>Не рекомендовано. ImgBed не потребує доступу до всього акаунта.</td></tr></tbody></table><p><img src="'+e+'" alt="Створення Dropbox app" loading="lazy"></p><h3 id="крок-2-додаите-redirect-uri" tabindex="-1">Крок 2. Додайте Redirect URI <a class="header-anchor" href="#крок-2-додаите-redirect-uri" aria-label="Permalink to &quot;Крок 2. Додайте Redirect URI&quot;">​</a></h3><p>На сторінці деталей Dropbox app знайдіть налаштування OAuth або Redirect URI й додайте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Якщо адмін-панель використовується з кількох доменів, додайте кожний відповідний callback URL.</p><p><img src="'+a+'" alt="Налаштування redirect URI" loading="lazy"></p><h3 id="крок-3-налаштуите-permissions-app" tabindex="-1">Крок 3. Налаштуйте permissions app <a class="header-anchor" href="#крок-3-налаштуите-permissions-app" aria-label="Permalink to &quot;Крок 3. Налаштуйте permissions app&quot;">​</a></h3><p>Відкрийте вкладку <code>Permissions</code> і ввімкніть щонайменше такі scopes:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Обов&#39;язково</th><th>Призначення</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Так</td><td>Читає інформацію про акаунт і квоту</td></tr><tr><td><code>files.metadata.read</code></td><td>Так</td><td>Читає метадані файлів і папок для перевірки шляхів</td></tr><tr><td><code>files.metadata.write</code></td><td>Так</td><td>Створює папки й записує метадані</td></tr><tr><td><code>files.content.write</code></td><td>Так</td><td>Завантажує файли. Без цього scope буде помилка <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Рекомендовано</td><td>Дозволяє завантаження, перегляд і тимчасові посилання на файли</td></tr></tbody></table><p>Після вибору scopes натисніть <code>Submit</code> унизу сторінки.</p><p><img src="'+d+'" alt="Додавання прав" loading="lazy"></p><p>Важливо:</p><table tabindex="0"><thead><tr><th>Ситуація</th><th>Що зробити</th></tr></thead><tbody><tr><td>Ви змінили scopes</td><td>Запустіть authorization flow ще раз і отримайте новий <code>Refresh Token</code>.</td></tr><tr><td>Ви не авторизувалися повторно</td><td>Старий token не отримає нові permissions, тому завантаження все ще може падати.</td></tr></tbody></table><h3 id="крок-4-скопіюите-credentials-app" tabindex="-1">Крок 4. Скопіюйте credentials app <a class="header-anchor" href="#крок-4-скопіюите-credentials-app" aria-label="Permalink to &quot;Крок 4. Скопіюйте credentials app&quot;">​</a></h3><p>Збережіть ці два значення зі сторінки Dropbox app:</p><table tabindex="0"><thead><tr><th>Поле Dropbox</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="крок-5-заповніть-канал-dropbox" tabindex="-1">Крок 5. Заповніть канал Dropbox <a class="header-anchor" href="#крок-5-заповніть-канал-dropbox" aria-label="Permalink to &quot;Крок 5. Заповніть канал Dropbox&quot;">​</a></h3><p>У налаштуваннях завантаження виберіть <code>Dropbox</code> і заповніть:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Зрозуміла назва, наприклад <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Поки залиште порожнім</td></tr><tr><td>Root directory</td><td>Необов&#39;язково. Типово <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Необов&#39;язково</td></tr></tbody></table><p><img src="'+o+'" alt="Отримання token" loading="lazy"></p><h3 id="крок-6-отримаите-refresh-token" tabindex="-1">Крок 6. Отримайте Refresh Token <a class="header-anchor" href="#крок-6-отримаите-refresh-token" aria-label="Permalink to &quot;Крок 6. Отримайте Refresh Token&quot;">​</a></h3><ol><li>В ImgBed натисніть <code>Get Token</code>.</li><li>Увійдіть у Dropbox-акаунт, який хочете підключити.</li><li>Підтвердьте запит авторизації.</li><li>На callback-сторінці з&#39;явиться <code>Refresh Token</code>.</li><li>Скопіюйте його.</li><li>Поверніться до ImgBed і вставте його в поле <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="Копіювання token" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Очікуваний результат</th></tr></thead><tbody><tr><td>Картка каналу</td><td>Dropbox-канал з&#39;являється після збереження.</td></tr><tr><td>Перемикач каналу</td><td>Канал можна ввімкнути.</td></tr><tr><td>Token збережено</td><td>На сторінці деталей видно, що <code>Refresh Token</code> збережено.</td></tr><tr><td>Тестове завантаження</td><td>Тестове зображення з&#39;являється в app folder Dropbox.</td></tr></tbody></table><p>Якщо ввімкнені quota limits, натисніть запит квоти. Після успішного запиту картка каналу показує використаний обсяг, загальний обсяг і час останнього оновлення.</p><p><img src="'+p+`" alt="Успішний запит квоти" loading="lazy"></p><h2 id="усунення-несправностеи" tabindex="-1">Усунення несправностей <a class="header-anchor" href="#усунення-несправностеи" aria-label="Permalink to &quot;Усунення несправностей&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проблема</th><th>Як виправити</th></tr></thead><tbody><tr><td>ImgBed повідомляє, що конфігурація неповна</td><td>Перевірте, що <code>App Key</code>, <code>App Secret</code> і <code>Refresh Token</code> усі заповнені.</td></tr><tr><td>Авторизація успішна, але <code>Refresh Token</code> не з&#39;являється</td><td>Натисніть <code>Get Token</code> ще раз і переконайтеся, що використовується offline authorization flow.</td></tr><tr><td>Завантаження падає з <code>required scope &#39;files.content.write&#39;</code></td><td>Увімкніть <code>files.content.write</code>, натисніть <code>Submit</code>, потім отримайте новий <code>Refresh Token</code>.</td></tr><tr><td>Callback не проходить</td><td>Переконайтеся, що redirect URI має вигляд <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Файли не знаходяться</td><td>Переконайтеся, що Dropbox app створений у режимі <code>App folder</code>.</td></tr></tbody></table><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити Dropbox App Console</span></span>
<span class="line"><span>-&gt; Створити app</span></span>
<span class="line"><span>-&gt; Вибрати App folder access</span></span>
<span class="line"><span>-&gt; Додати https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Увімкнути account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; За бажанням увімкнути files.content.read</span></span>
<span class="line"><span>-&gt; Натиснути Submit</span></span>
<span class="line"><span>-&gt; Скопіювати App Key і App Secret</span></span>
<span class="line"><span>-&gt; Ввести їх в ImgBed</span></span>
<span class="line"><span>-&gt; Натиснути Get Token</span></span>
<span class="line"><span>-&gt; Скопіювати Refresh Token з callback-сторінки</span></span>
<span class="line"><span>-&gt; Вставити його назад в ImgBed і зберегти</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const _=s(c,[["render",h]]);export{y as __pageData,_ as default};
